sql:
SELECT SUM(count) AS total_frames
FROM frame_statistics
WHERE port_id = 1 AND frame_type_id = 1;

SELECT error_description
FROM error_frames
WHERE port_id = 0 AND error_type_id = 0;

SELECT MAX(timestamp) AS latest_alarm_timestamp
FROM alarms
WHERE port_id = 1;

SELECT COUNT(*) AS active_ports_count
  FROM ports
  WHERE device_id = 1 AND status = 'active';

SELECT SUM(count) AS total_error_frames
FROM error_frames
WHERE port_id = 1 AND error_type_id = (SELECT error_type_id FROM error_types WHERE error_type_name = 'invalid FCS');

SELECT SUM(count) AS total_errors
FROM error_frames
WHERE port_id = 0;

SELECT MAX(count) AS max_error_count
FROM error_frames
WHERE port_id = 1;

SELECT MAX(mtu) AS max_mtu
FROM ports
WHERE status = 'active';

SELECT SUM(count) AS total_frames, SUM(bytes_transferred) AS total_bytes
FROM frame_statistics
WHERE port_id = 1;

SELECT port_name, status
FROM ports
ORDER BY port_name;

external_knowledge:
Error types are ranked based on the total count of frames in descending order; 
A device is associated with multiple ports; 
Ports can be located in different places.
